contracts/PolicyEngine.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./IPolicyEngine.sol";

/**
 * @title PolicyEngine
 * @notice Stores and validates spending policies for ARC-402 wallets
 * STATUS: DRAFT — not audited, do not use in production
 */
contract PolicyEngine is IPolicyEngine {
    struct PolicyData {
        bytes32 policyHash;
        bytes policyData;
        uint256 updatedAt;
    }

    mapping(address => PolicyData) private policies;
    mapping(address => mapping(string => uint256)) public categoryLimits;
    mapping(address => address) public walletOwners;

    event PolicySet(address indexed wallet, bytes32 policyHash);
    event CategoryLimitSet(address indexed wallet, string category, uint256 limitPerTx);

    // Called by wallet to register itself
    function registerWallet(address wallet, address owner) external {
        walletOwners[wallet] = owner;
    }

    function setPolicy(bytes32 policyHash, bytes calldata policyData) external {
        policies[msg.sender] = PolicyData({
            policyHash: policyHash,
            policyData: policyData,
            updatedAt: block.timestamp
        });
        emit PolicySet(msg.sender, policyHash);
    }

    function getPolicy(address wallet) external view returns (bytes32, bytes memory) {
        PolicyData storage p = policies[wallet];
        return (p.policyHash, p.policyData);
    }

    function setCategoryLimit(string calldata category, uint256 limitPerTx) external {
        categoryLimits[msg.sender][category] = limitPerTx;
        emit CategoryLimitSet(msg.sender, category, limitPerTx);
    }

    function setCategoryLimitFor(address wallet, string calldata category, uint256 limitPerTx) external {
        // Allow owner to set limits for their wallet
        require(walletOwners[wallet] == msg.sender || wallet == msg.sender, "PolicyEngine: not authorized");
        categoryLimits[wallet][category] = limitPerTx;
        emit CategoryLimitSet(wallet, category, limitPerTx);
    }

    function validateSpend(
        address wallet,
        string calldata category,
        uint256 amount,
        bytes32 /*contextId*/
    ) external view returns (bool valid, string memory reason) {
        uint256 limit = categoryLimits[wallet][category];
        if (limit == 0) {
            return (false, "PolicyEngine: category not configured");
        }
        if (amount > limit) {
            return (false, "PolicyEngine: amount exceeds category limit");
        }
        return (true, "");
    }
}

contracts/SettlementCoordinator.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/**
 * @title SettlementCoordinator
 * @notice Multi-Agent Settlement coordinator for ARC-402
 * STATUS: DRAFT — not audited, do not use in production
 */
contract SettlementCoordinator {
    enum ProposalStatus { PENDING, ACCEPTED, REJECTED, EXECUTED, EXPIRED }

    struct Proposal {
        bytes32 proposalId;
        address fromWallet;
        address toWallet;
        uint256 amount;
        bytes32 intentId;
        uint256 expiresAt;
        ProposalStatus status;
        string rejectionReason;
    }

    mapping(bytes32 => Proposal) private proposals;
    mapping(bytes32 => bool) private proposalExists;

    event ProposalCreated(bytes32 indexed proposalId, address indexed from, address indexed to, uint256 amount);
    event ProposalAccepted(bytes32 indexed proposalId);
    event ProposalRejected(bytes32 indexed proposalId, string reason);
    event ProposalExecuted(bytes32 indexed proposalId, uint256 amount);
    event ProposalExpired(bytes32 indexed proposalId);

    function propose(
        address fromWallet,
        address toWallet,
        uint256 amount,
        bytes32 intentId,
        uint256 expiresAt
    ) external returns (bytes32 proposalId) {
        proposalId = keccak256(abi.encodePacked(fromWallet, toWallet, amount, intentId, block.timestamp));
        require(!proposalExists[proposalId], "SettlementCoordinator: proposal exists");

        proposals[proposalId] = Proposal({
            proposalId: proposalId,
            fromWallet: fromWallet,
            toWallet: toWallet,
            amount: amount,
            intentId: intentId,
            expiresAt: expiresAt,
            status: ProposalStatus.PENDING,
            rejectionReason: ""
        });
        proposalExists[proposalId] = true;

        emit ProposalCreated(proposalId, fromWallet, toWallet, amount);
        return proposalId;
    }

    function accept(bytes32 proposalId) external {
        Proposal storage p = proposals[proposalId];
        require(proposalExists[proposalId], "SettlementCoordinator: not found");
        require(p.status == ProposalStatus.PENDING, "SettlementCoordinator: not pending");
        require(block.timestamp <= p.expiresAt, "SettlementCoordinator: expired");
        require(msg.sender == p.toWallet, "SettlementCoordinator: not recipient");

        p.status = ProposalStatus.ACCEPTED;
        emit ProposalAccepted(proposalId);
    }

    function reject(bytes32 proposalId, string calldata reason) external {
        Proposal storage p = proposals[proposalId];
        require(proposalExists[proposalId], "SettlementCoordinator: not found");
        require(p.status == ProposalStatus.PENDING, "SettlementCoordinator: not pending");
        require(msg.sender == p.toWallet, "SettlementCoordinator: not recipient");

        p.status = ProposalStatus.REJECTED;
        p.rejectionReason = reason;
        emit ProposalRejected(proposalId, reason);
    }

    function execute(bytes32 proposalId) external payable {
        Proposal storage p = proposals[proposalId];
        require(proposalExists[proposalId], "SettlementCoordinator: not found");
        require(p.status == ProposalStatus.ACCEPTED, "SettlementCoordinator: not accepted");
        require(block.timestamp <= p.expiresAt, "SettlementCoordinator: expired");
        require(msg.sender == p.fromWallet, "SettlementCoordinator: not sender");
        require(msg.value == p.amount, "SettlementCoordinator: wrong amount");

        p.status = ProposalStatus.EXECUTED;

        emit ProposalExecuted(proposalId, p.amount);
        (bool success,) = p.toWallet.call{value: p.amount}("");
        require(success, "SettlementCoordinator: transfer failed");
    }

    function getProposal(bytes32 proposalId) external view returns (
        address fromWallet,
        address toWallet,
        uint256 amount,
        bytes32 intentId,
        uint256 expiresAt,
        ProposalStatus status,
        string memory rejectionReason
    ) {
        require(proposalExists[proposalId], "SettlementCoordinator: not found");
        Proposal storage p = proposals[proposalId];
        return (p.fromWallet, p.toWallet, p.amount, p.intentId, p.expiresAt, p.status, p.rejectionReason);
    }

    function checkExpiry(bytes32 proposalId) external {
        Proposal storage p = proposals[proposalId];
        require(proposalExists[proposalId], "SettlementCoordinator: not found");
        require(p.status == ProposalStatus.PENDING, "SettlementCoordinator: not pending");
        require(block.timestamp > p.expiresAt, "SettlementCoordinator: not expired");
        p.status = ProposalStatus.EXPIRED;
        emit ProposalExpired(proposalId);
    }
}

contracts/TrustRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./ITrustRegistry.sol";

/**
 * @title TrustRegistry
 * @notice On-chain trust scores for ARC-402 wallets (0–1000)
 * STATUS: DRAFT — not audited, do not use in production
 */
contract TrustRegistry is ITrustRegistry {
    uint256 public constant MAX_SCORE = 1000;
    uint256 public constant INITIAL_SCORE = 100;
    uint256 public constant INCREMENT = 5;
    uint256 public constant DECREMENT = 20;

    mapping(address => uint256) private scores;
    mapping(address => bool) private initialized;
    mapping(address => bool) public isAuthorizedUpdater;
    address public owner;

    event WalletInitialized(address indexed wallet, uint256 score);
    event ScoreUpdated(address indexed wallet, uint256 oldScore, uint256 newScore, string reason);
    event UpdaterAdded(address indexed updater);
    event UpdaterRemoved(address indexed updater);
    event OwnershipTransferred(address indexed oldOwner, address indexed newOwner);

    constructor() {
        owner = msg.sender;
        isAuthorizedUpdater[msg.sender] = true;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "TrustRegistry: not owner");
        _;
    }

    modifier onlyUpdater() {
        require(isAuthorizedUpdater[msg.sender], "TrustRegistry: not authorized updater");
        _;
    }

    function addUpdater(address updater) external onlyOwner {
        isAuthorizedUpdater[updater] = true;
        emit UpdaterAdded(updater);
    }

    function removeUpdater(address updater) external onlyOwner {
        isAuthorizedUpdater[updater] = false;
        emit UpdaterRemoved(updater);
    }

    function transferOwnership(address newOwner) external onlyOwner {
        require(newOwner != address(0), "TrustRegistry: zero address");
        address old = owner;
        owner = newOwner;
        emit OwnershipTransferred(old, newOwner);
    }

    function renounceOwnership() external onlyOwner {
        address old = owner;
        owner = address(0);
        emit OwnershipTransferred(old, address(0));
    }

    function initWallet(address wallet) external {
        if (!initialized[wallet]) {
            initialized[wallet] = true;
            scores[wallet] = INITIAL_SCORE;
            emit WalletInitialized(wallet, INITIAL_SCORE);
        }
    }

    function getScore(address wallet) external view returns (uint256) {
        if (!initialized[wallet]) return 0;
        return scores[wallet];
    }

    function recordSuccess(address wallet) external onlyUpdater {
        if (!initialized[wallet]) {
            initialized[wallet] = true;
            scores[wallet] = INITIAL_SCORE;
        }
        uint256 oldScore = scores[wallet];
        uint256 newScore = oldScore + INCREMENT > MAX_SCORE ? MAX_SCORE : oldScore + INCREMENT;
        scores[wallet] = newScore;
        emit ScoreUpdated(wallet, oldScore, newScore, "success");
    }

    function recordAnomaly(address wallet) external onlyUpdater {
        if (!initialized[wallet]) {
            initialized[wallet] = true;
            scores[wallet] = INITIAL_SCORE;
        }
        uint256 oldScore = scores[wallet];
        uint256 newScore = oldScore < DECREMENT ? 0 : oldScore - DECREMENT;
        scores[wallet] = newScore;
        emit ScoreUpdated(wallet, oldScore, newScore, "anomaly");
    }

    function getTrustLevel(address wallet) external view returns (string memory) {
        uint256 score = scores[wallet];
        if (!initialized[wallet]) return "probationary";
        if (score < 100) return "probationary";
        if (score < 300) return "restricted";
        if (score < 600) return "standard";
        if (score < 800) return "elevated";
        return "autonomous";
    }
}

